trigger.body:
    v_count integer;
BEGIN
    IF AD_isTriggerEnabled () = 'N' THEN
        IF DELETING THEN
            RETURN OLD;
        ELSE
            RETURN NEW;
        END IF;
    END IF;
    -- Verificar registros Nombres duplicados
    -- Validación en INSERT
    IF(INSERTING OR UPDATING) THEN
        SELECT
            count(*) INTO v_count
        FROM
            ecsba_breakdown
        WHERE
            upper(name) = upper(trim(:NEW.name))
            AND ecsba_module_id = :NEW.ecsba_module_id

            AND ecsba_breakdown_ID <> COALESCE(:NEW.ecsba_breakdown_ID, '0'); 

        IF (v_count > 0) THEN
            RAISE_APPLICATION_ERROR(-20000, '@ECSBA_DuplicateName@');
        END IF;
    END IF;
    END ECSBA_BREAKDOWN_CKNAME_TRG
